// // This module controls power gating based on the power_on signal and load_current. It outputs gated_power as 1 only when power_on is 0 and load_current is above 10.
module power_gating_controller(
    input wire power_on,
    input wire [7:0] load_current,
    output wire gated_power
);

assign gated_power = power_on && (load_current < 8'd10);

endmodule
